import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [user, setUser] = useState(null);
  const [agents, setAgents] = useState([]);
  const [selectedAgent, setSelectedAgent] = useState('');
  const [input, setInput] = useState('');
  const [chatHistory, setChatHistory] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isLogin, setIsLogin] = useState(true);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [selectedFile, setSelectedFile] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      setUser({ token });
      fetchAgents(token);
    }
  }, []);

  const fetchAgents = async (token) => {
    try {
      const res = await axios.get('/api/agents', {
        headers: { Authorization: `Bearer ${token}` },
      });
      setAgents(res.data);
    } catch (err) {
      console.error('Failed to fetch agents:', err);
    }
  };

  const handleLoginRegister = async () => {
    try {
      const url = isLogin ? '/api/login' : '/api/register';
      const res = await axios.post(url, { username, password });
      localStorage.setItem('token', res.data.token);
      setUser({ token: res.data.token });
      setIsModalOpen(false);
      fetchAgents(res.data.token);
    } catch (err) {
      alert('Authentication failed.');
    }
  };

  const handleChat = async () => {
    if (!input || !selectedAgent) return;
    try {
      const res = await axios.post(
        '/api/chat',
        { message: input, agentId: selectedAgent },
        { headers: { Authorization: `Bearer ${user.token}` } }
      );
      setChatHistory([
        ...chatHistory,
        { role: 'user', content: input },
        { role: 'agent', content: res.data.reply },
      ]);
      setInput('');
    } catch (err) {
      console.error('Chat failed:', err);
    }
  };

  const handleFileChange = (e) => {
    setSelectedFile(e.target.files[0]);
  };

  const handleFileUpload = async () => {
    if (!selectedFile || !selectedAgent) return;
    const formData = new FormData();
    formData.append('file', selectedFile);
    formData.append('agentId', selectedAgent);

    try {
      await axios.post('/api/upload', formData, {
        headers: {
          Authorization: `Bearer ${user.token}`,
          'Content-Type': 'multipart/form-data',
        },
      });
      alert('File uploaded successfully.');
    } catch (err) {
      alert('File upload failed.');
    }
  };

  return (
    <div className="App">
      <header className="header">
        <img src="/logo.png" alt="AI-MMI Logo" className="header-icon" />
        <h1 className="header-title">AI-MMI Immigration Assistant</h1>
      </header>

      {!user ? (
        <button className="auth-button" onClick={() => setIsModalOpen(true)}>
          Login / Register
        </button>
      ) : (
        <>
          <select
            onChange={(e) => setSelectedAgent(e.target.value)}
            className="dropdown"
            value={selectedAgent}
          >
            <option value="">Select an Agent</option>
            {agents.map((agent) => (
              <option key={agent._id} value={agent._id}>
                {agent.name}
              </option>
            ))}
          </select>

          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type your message here..."
            className="chat-input"
          />
          <button onClick={handleChat} className="send-button">
            Send
          </button>

          {user && (
            <div className="file-upload">
              <input type="file" onChange={handleFileChange} />
              <button onClick={handleFileUpload}>Upload File</button>
            </div>
          )}

          <div className="chat-history">
            {chatHistory?.map((msg, i) => (
              <div key={i} className={`chat-message ${msg.role}`}>
                <strong>{msg.role === 'user' ? 'You' : 'Agent'}:</strong> {msg.content}
              </div>
            ))}
          </div>
        </>
      )}

      {isModalOpen && (
        <div className="modal">
          <h2>{isLogin ? 'Login' : 'Register'}</h2>
          <input
            type="text"
            placeholder="Username"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
          />
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <button onClick={handleLoginRegister}>
            {isLogin ? 'Login' : 'Register'}
          </button>
          <button
            onClick={() => setIsLogin(!isLogin)}
            className="toggle-button"
          >
            {isLogin ? 'Need to register?' : 'Have an account? Login'}
          </button>
        </div>
      )}

      <div className="agent-list">
        {agents.map((agent) => (
          <div key={agent._id}>
            <strong>{agent.name}</strong>: {agent.description}
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
